import { normalizeSpeed, parsePriceToCents } from "../../validators";
import { parseHTML } from "../dom-utils";
function extractUploadSpeed(planElement, downloadSpeed) {
    if (!downloadSpeed)
        return null;
    const planText = planElement.textContent || "";
    const uploadMatch = planText.match(/(\d+)\s*Mbps\s*(up|upload|↑)/i);
    if (uploadMatch) {
        return parseInt(uploadMatch[1]);
    }
    const uploadRatios = {
        12: 1, 25: 1, 50: 2, 100: 10, 200: 20, 250: 20, 400: 40, 500: 40, 1000: 50, 2000: 100,
    };
    return uploadRatios[downloadSpeed] || null;
}
function extractDataAllowance(planElement) {
    const planText = (planElement.textContent || "").toLowerCase();
    if (planText.includes("unlimited"))
        return "Unlimited";
    const amountMatch = planText.match(/(\d+\.?\d*)\s*(tb|gb)/i);
    return amountMatch ? `${amountMatch[1]}${amountMatch[2].toUpperCase()}` : null;
}
function extractContractMonths(planElement) {
    const planText = (planElement.textContent || "").toLowerCase();
    if (planText.includes("no contract") || planText.includes("month-to-month"))
        return 0;
    if (planText.includes("24 month") || planText.includes("2 year"))
        return 24;
    if (planText.includes("12 month") || planText.includes("1 year"))
        return 12;
    return null;
}
function extractModemIncluded(planElement) {
    const planText = (planElement.textContent || "").toLowerCase();
    if (planText.includes("modem included") || planText.includes("router included") || planText.includes("free modem"))
        return true;
    if (planText.includes("modem $") || planText.includes("bring your own") || planText.includes("your own modem"))
        return false;
    return null;
}
function extractSetupFee(planElement) {
    const planText = planElement.textContent || "";
    if (planText.match(/free\s*(setup|connection|installation)/i))
        return 0;
    const feeMatch = planText.match(/(setup|connection|installation)[\s:]*\$(\d+(?:\.\d{2})?)/i);
    return feeMatch ? Math.round(parseFloat(feeMatch[2]) * 100) : null;
}
function extractIntroOffer(text) {
    const introMatch = text.match(/\$\s*([0-9]+(?:\.[0-9]{1,2})?)\s*(?:\/mo|\/month|per\s*month|pm)?\s*(?:for|first)\s*(\d{1,2})\s*(?:months|month|mo)/i);
    const thenMatch = text.match(/then\s*\$\s*([0-9]+(?:\.[0-9]{1,2})?)/i);
    const introPriceCents = introMatch ? parsePriceToCents(introMatch[1]) : null;
    const introDurationDays = introMatch ? parseInt(introMatch[2], 10) * 30 : null;
    const thenPriceCents = thenMatch ? parsePriceToCents(thenMatch[1]) : null;
    const promoDescription = introMatch ? introMatch[0].trim() : null;
    return { introPriceCents, introDurationDays, thenPriceCents, promoDescription };
}
export function canHandle(url) {
    return url.includes("iinet.net.au") || url.includes("iinet.com.au");
}
export async function parse(html, url) {
    const doc = parseHTML(html);
    const results = [];
    // Try main plan containers
    let rows = Array.from(doc.querySelectorAll(".plan, .plan-box, .product-item, [class*='plan-']"));
    if (rows.length === 0) {
        // Fallback: look for sections with speed info
        rows = Array.from(doc.querySelectorAll("section, .pricing-section, [class*='plan-section']")).filter(el => /NBN|speed|plan/i.test(el.textContent || ""));
    }
    for (const el of rows) {
        const speedText = (el.textContent || "").match(/NBN\s*(\d{1,4})/i) ||
            (el.textContent || "").match(/(\d{1,4})\s*Mbps/i);
        if (!speedText)
            continue;
        const parsedSpeed = parseInt(speedText[1]);
        const speedTier = normalizeSpeed(parsedSpeed);
        if (!speedTier)
            continue;
        const priceText = el.querySelector(".price, .plan-price, [class*='price']")?.textContent || el.textContent || "";
        const introOffer = extractIntroOffer(el.textContent || "");
        results.push({
            providerSlug: "iinet",
            planName: (el.querySelector("h4, h5, .product-name, [class*='name']")?.textContent || "").trim() || `NBN ${speedTier}`,
            speedTier,
            uploadSpeedMbps: extractUploadSpeed(el, speedTier),
            dataAllowance: extractDataAllowance(el),
            contractMonths: extractContractMonths(el),
            modemIncluded: extractModemIncluded(el),
            introPriceCents: introOffer.introPriceCents ?? parsePriceToCents(priceText),
            introDurationDays: introOffer.introDurationDays,
            ongoingPriceCents: introOffer.thenPriceCents ?? parsePriceToCents(priceText),
            minTermDays: null,
            setupFeeCents: extractSetupFee(el),
            modemCostCents: null,
            conditionsText: (el.textContent || "").trim() || null,
            promoDescription: introOffer.promoDescription,
            typicalEveningSpeedMbps: null,
            sourceUrl: url,
        });
    }
    return results;
}
